import { useState, useEffect } from 'react';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [projects, setProjects] = useState([]);
  const [projectTaskMap, setProjectTaskMap] = useState({});
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  const fetchData = async () => {
    try {
      setLoading(true);

      if (user?.role === 'admin') {
        const projectsRes = await API.get('/projects');
        const allProjects = projectsRes.data.projects || projectsRes.data;

        setProjects(allProjects);

        const taskPromises = allProjects.map(p =>
          API.get(`/tasks?project=${p._id}`)
        );

        const taskResults = await Promise.all(taskPromises);
        const allTasks = taskResults.flatMap(r => r.data.tasks || r.data);

        setTasks(allTasks);

        const map = {};
        allProjects.forEach((p, i) => {
          map[p._id] = {
            name: p.name,
            tasks: taskResults[i].data.tasks || taskResults[i].data,
          };
        });

        setProjectTaskMap(map);

      } else {
        const [tasksRes, projectsRes] = await Promise.all([
          API.get('/tasks/my-tasks'),
          API.get('/projects'),
        ]);

        const myTasks = tasksRes.data.tasks || tasksRes.data;
        const myProjects = projectsRes.data;

        setTasks(myTasks);
        setProjects(myProjects);

        const map = {};
        myProjects.forEach(p => {
          const projectTasks = myTasks.filter(
            t => t.project?._id === p._id || t.project === p._id
          );
          map[p._id] = { name: p.name, tasks: projectTasks };
        });

        setProjectTaskMap(map);
      }

    } catch (err) {
      console.error('Dashboard load error:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [user]);

  // 🔥 FIXED STATS (progress-based)
  const total = tasks.length;
  const todo = tasks.filter(t => !t.progress || t.progress === 0).length;
  const inProgress = tasks.filter(t => t.progress > 0 && t.progress < 100).length;
  const done = tasks.filter(t => t.progress === 100).length;

  const overdue = tasks.filter(t => {
    const due = t.dueDate || t.deadline;
    return due && new Date(due) < new Date() && t.progress !== 100;
  }).length;

  const stats = [
    { label: 'My Tasks', value: total },
    { label: 'To Do', value: todo },
    { label: 'In Progress', value: inProgress },
    { label: 'Completed', value: done },
    { label: 'Overdue', value: overdue },
  ];

  if (loading) return <p>Loading...</p>;

  return (
    <div style={styles.page}>

      {/* HEADER */}
      <div style={styles.header}>
        <div>
          <h2>👋 Welcome back, {user?.name}!</h2>
          <p>Your personal progress & task summary</p>
        </div>
        <div style={styles.role}>
          {user?.role}
        </div>
      </div>

      {/* STATS */}
      <div style={styles.stats}>
        {stats.map((s) => (
          <div key={s.label} style={styles.card}>
            <h2>{s.value}</h2>
            <p>{s.label}</p>
          </div>
        ))}
      </div>

      {/* PROJECT PROGRESS */}
      <div style={styles.section}>
        <h3>📁 My Progress by Project</h3>

        {projects.length === 0 ? (
          <p>No projects yet</p>
        ) : (
          projects.map((proj) => {
            const projectTasks = projectTaskMap[proj._id]?.tasks || [];

            const total = projectTasks.length;
            const done = projectTasks.filter(t => t.progress === 100).length;
            const pct = total ? Math.round((done / total) * 100) : 0;

            return (
              <div key={proj._id} style={styles.project}>
                <strong>{proj.name}</strong>

                <div style={styles.bar}>
                  <div style={{
                    width: `${pct}%`,
                    background: '#6366f1',
                    height: '100%',
                  }} />
                </div>

                <small>{pct}% completed</small>
              </div>
            );
          })
        )}
      </div>

    </div>
  );
};

const styles = {
  page: { maxWidth: '900px', margin: 'auto' },

  header: {
    display: 'flex',
    justifyContent: 'space-between',
    marginBottom: '20px',
  },

  role: {
    background: '#6366f1',
    color: 'white',
    padding: '8px 15px',
    borderRadius: '20px',
  },

  stats: {
    display: 'flex',
    gap: '15px',
    marginBottom: '20px',
  },

  card: {
    flex: 1,
    background: '#f5f5f5',
    padding: '20px',
    borderRadius: '10px',
    textAlign: 'center',
  },

  section: {
    background: 'white',
    padding: '20px',
    borderRadius: '10px',
  },

  project: {
    marginBottom: '15px',
  },

  bar: {
    height: '8px',
    background: '#eee',
    borderRadius: '5px',
    marginTop: '5px',
    overflow: 'hidden',
  },
};

export default Dashboard;
